CodeSnippet.Text:
[comment]# Az Orchard Core CMS-csomag hozzáadása[/comment]
$ [cmd]dotnet[/cmd] add package [name]OrchardCore.Application.Cms.Targets[/name]

[comment]// Program.cs: teljes CMS hozzáadása egy ASP.NET Core-alkalmazáshoz[/comment]
[cmd]var[/cmd] builder = [type]WebApplication[/type].CreateBuilder(args);

builder.Services.[name]AddOrchardCms[/name]();

[cmd]var[/cmd] app = builder.Build();

app.[name]UseStaticFiles[/name]();
app.[name]UseOrchardCore[/name]();

app.[name]Run[/name]();
